#include <stdio.h>
#include <stdlib.h>
#include <sys/time.h>
#include <cuda_runtime.h>

long long get_time()
{
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

using namespace std;

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE 256

#define MAX_PD (3.0e6)

#define PRECISION 0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100

#define FACTOR_CHIP 0.5
#define OPEN

typedef float FLOAT;

const FLOAT t_chip = 0.0005;
const FLOAT chip_height = 0.016;
const FLOAT chip_width = 0.016;
const FLOAT amb_temp = 80.0;

int num_omp_threads;

static inline void cuda_check(cudaError_t err, const char *msg)
{
    if (err != cudaSuccess)
    {
        fprintf(stderr, "error: %s: %s\n", msg, cudaGetErrorString(err));
        exit(1);
    }
}

__global__ void single_iteration_kernel(FLOAT *result, const FLOAT *temp, const FLOAT *power,
                                        int row, int col, FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1)
{
    int c = blockIdx.x * blockDim.x + threadIdx.x;
    int r = blockIdx.y * blockDim.y + threadIdx.y;

    if (r >= row || c >= col)
        return;

    int idx = r * col + c;
    FLOAT delta;

    if ((r == 0) && (c == 0))
    {
        delta = (Cap_1) * (power[0] +
                           (temp[1] - temp[0]) * Rx_1 +
                           (temp[col] - temp[0]) * Ry_1 +
                           (amb_temp - temp[0]) * Rz_1);
        result[idx] = temp[idx] + delta;
    }
    else if ((0 == r) && (col - 1 == c))
    {
        delta = (Cap_1) * (power[c] +
                           (temp[c - 1] - temp[c]) * Rx_1 +
                           (temp[c + col] - temp[c]) * Ry_1 +
                           (amb_temp - temp[c]) * Rz_1);
        result[idx] = temp[idx] + delta;
    }
    else if ((row - 1 == r) && (col - 1 == c))
    {
        delta = (Cap_1) * (power[r * col + c] +
                           (temp[r * col + c - 1] - temp[r * col + c]) * Rx_1 +
                           (temp[(r - 1) * col + c] - temp[r * col + c]) * Ry_1 +
                           (amb_temp - temp[r * col + c]) * Rz_1);
        result[idx] = temp[idx] + delta;
    }
    else if ((r == row - 1) && (0 == c))
    {
        delta = (Cap_1) * (power[r * col] +
                           (temp[r * col + 1] - temp[r * col]) * Rx_1 +
                           (temp[(r - 1) * col] - temp[r * col]) * Ry_1 +
                           (amb_temp - temp[r * col]) * Rz_1);
        result[idx] = temp[idx] + delta;
    }
    else if (0 == r)
    {
        delta = (Cap_1) * (power[c] +
                           (temp[c + 1] + temp[c - 1] - 2.0 * temp[c]) * Rx_1 +
                           (temp[col + c] - temp[c]) * Ry_1 +
                           (amb_temp - temp[c]) * Rz_1);
        result[idx] = temp[idx] + delta;
    }
    else if (col - 1 == c)
    {
        delta = (Cap_1) * (power[r * col + c] +
                           (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0 * temp[r * col + c]) * Ry_1 +
                           (temp[r * col + c - 1] - temp[r * col + c]) * Rx_1 +
                           (amb_temp - temp[r * col + c]) * Rz_1);
        result[idx] = temp[idx] + delta;
    }
    else if (row - 1 == r)
    {
        delta = (Cap_1) * (power[r * col + c] +
                           (temp[r * col + c + 1] + temp[r * col + c - 1] - 2.0 * temp[r * col + c]) * Rx_1 +
                           (temp[(r - 1) * col + c] - temp[r * col + c]) * Ry_1 +
                           (amb_temp - temp[r * col + c]) * Rz_1);
        result[idx] = temp[idx] + delta;
    }
    else if (c == 0)
    {
        delta = (Cap_1) * (power[r * col] +
                           (temp[(r + 1) * col] + temp[(r - 1) * col] - 2.0 * temp[r * col]) * Ry_1 +
                           (temp[r * col + 1] - temp[r * col]) * Rx_1 +
                           (amb_temp - temp[r * col]) * Rz_1);
        result[idx] = temp[idx] + delta;
    }
    else
    {
        result[idx] = temp[idx] +
                      (Cap_1 * (power[r * col + c] +
                                (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.f * temp[r * col + c]) * Ry_1 +
                                (temp[r * col + c + 1] + temp[r * col + c - 1] - 2.f * temp[r * col + c]) * Rx_1 +
                                (amb_temp - temp[r * col + c]) * Rz_1));
    }
}

void single_iteration(FLOAT *result, FLOAT *temp, FLOAT *power, int row, int col,
                      FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1,
                      FLOAT step)
{
    (void)step;
    dim3 block(BLOCK_SIZE_C, BLOCK_SIZE_R);
    dim3 grid((col + BLOCK_SIZE_C - 1) / BLOCK_SIZE_C, (row + BLOCK_SIZE_R - 1) / BLOCK_SIZE_R);
    single_iteration_kernel<<<grid, block>>>(result, temp, power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);
}

void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col)
{
#ifdef VERBOSE
    int i = 0;
#endif

    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0;

    FLOAT Rx_1 = 1.f / Rx;
    FLOAT Ry_1 = 1.f / Ry;
    FLOAT Rz_1 = 1.f / Rz;
    FLOAT Cap_1 = step / Cap;

#ifdef VERBOSE
    fprintf(stdout, "total iterations: %d s\tstep size: %g s\n", num_iterations, step);
    fprintf(stdout, "Rx: %g\tRy: %g\tRz: %g\tCap: %g\n", Rx, Ry, Rz, Cap);
#endif

    int array_size = row * col;
    size_t bytes = (size_t)array_size * sizeof(FLOAT);

    FLOAT *d_temp = NULL, *d_power = NULL, *d_result = NULL;
    cuda_check(cudaMalloc((void **)&d_temp, bytes), "cudaMalloc d_temp failed");
    cuda_check(cudaMalloc((void **)&d_power, bytes), "cudaMalloc d_power failed");
    cuda_check(cudaMalloc((void **)&d_result, bytes), "cudaMalloc d_result failed");

    cuda_check(cudaMemcpy(d_temp, temp, bytes, cudaMemcpyHostToDevice), "cudaMemcpy temp H2D failed");
    cuda_check(cudaMemcpy(d_power, power, bytes, cudaMemcpyHostToDevice), "cudaMemcpy power H2D failed");
    cuda_check(cudaMemcpy(d_result, result, bytes, cudaMemcpyHostToDevice), "cudaMemcpy result H2D failed");

    FLOAT *r = d_result;
    FLOAT *t = d_temp;

    for (int i = 0; num_iterations > i; i++)
    {
#ifdef VERBOSE
        fprintf(stdout, "iteration %d\n", i++);
#endif
        single_iteration(r, t, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1, step);
        FLOAT *tmp = t;
        t = r;
        r = tmp;
    }

    cuda_check(cudaDeviceSynchronize(), "kernel execution failed");

    cuda_check(cudaMemcpy(temp, d_temp, bytes, cudaMemcpyDeviceToHost), "cudaMemcpy temp D2H failed");
    cuda_check(cudaMemcpy(result, d_result, bytes, cudaMemcpyDeviceToHost), "cudaMemcpy result D2H failed");

    cudaFree(d_temp);
    cudaFree(d_power);
    cudaFree(d_result);

#ifdef VERBOSE
    fprintf(stdout, "iteration %d\n", i++);
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
    exit(1);
}

void writeoutput(FLOAT *vect, int grid_rows, int grid_cols, char *file)
{
    int i, j, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = fopen(file, "w")) == 0)
        printf("The file was not opened\n");

    for (i = 0; grid_rows > i; i++)
        for (j = 0; j < grid_cols; j++)
        {
            sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j]);
            fputs(str, fp);
            index++;
        }

    fclose(fp);
}

void read_input(FLOAT *vect, int grid_rows, int grid_cols, char *file)
{
    int i, index;
    FILE *fp;
    char str[STR_SIZE];
    FLOAT val;

    fp = fopen(file, "r");
    if (!fp)
        fatal((char *)"file could not be opened for reading");

    for (i = 0; grid_rows * grid_cols > i; i++)
    {
        (void)index;
        fgets(str, STR_SIZE, fp);
        if (feof(fp))
            fatal((char *)"not enough lines in file");
        if ((sscanf(str, "%f", &val) != 1))
            fatal((char *)"invalid file format");
        vect[i] = val;
    }

    fclose(fp);
}

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <grid_rows> <grid_cols> <sim_time> <no. of threads><temp_file> <power_file>\n", argv[0]);
    fprintf(stderr, "\t<grid_rows>  - number of rows in the grid (positive integer)\n");
    fprintf(stderr, "\t<grid_cols>  - number of columns in the grid (positive integer)\n");
    fprintf(stderr, "\t<sim_time>   - number of iterations\n");
    fprintf(stderr, "\t<no. of threads>   - number of threads\n");
    fprintf(stderr, "\t<temp_file>  - name of the file containing the initial temperature values of each cell\n");
    fprintf(stderr, "\t<power_file> - name of the file containing the dissipated power values of each cell\n");
    fprintf(stderr, "\t<output_file> - name of the output file\n");
    exit(1);
}

int main(int argc, char **argv)
{
    int grid_rows, grid_cols, sim_time, i;
    FLOAT *temp, *power, *result;
    char *tfile, *pfile, *ofile;

    if (argc != 8)
        usage(argc, argv);
    if ((grid_rows = atoi(argv[1])) <= 0 ||
        (grid_cols = atoi(argv[2])) <= 0 ||
        (sim_time = atoi(argv[3])) <= 0 ||
        (num_omp_threads = atoi(argv[4])) <= 0)
        usage(argc, argv);

    temp = (FLOAT *)calloc(grid_rows * grid_cols, sizeof(FLOAT));
    power = (FLOAT *)calloc(grid_rows * grid_cols, sizeof(FLOAT));
    result = (FLOAT *)calloc(grid_rows * grid_cols, sizeof(FLOAT));
    if (!temp || !power)
        fatal((char *)"unable to allocate memory");

    tfile = argv[5];
    pfile = argv[6];
    ofile = argv[7];

    read_input(temp, grid_rows, grid_cols, tfile);
    read_input(power, grid_rows, grid_cols, pfile);

    printf("Start computing the transient temperature\n");

    long long start_time = get_time();

    compute_tran_temp(result, sim_time, temp, power, grid_rows, grid_cols);

    long long end_time = get_time();

    printf("Ending simulation\n");
    printf("Total time: %.3f seconds\n", ((float)(end_time - start_time)) / (1000 * 1000));

    writeoutput((1 & sim_time) ? result : temp, grid_rows, grid_cols, ofile);

#ifdef VERBOSE
    fprintf(stdout, "Final Temperatures:\n");
#endif

#ifdef OUTPUT
    for (i = 0; i < grid_rows * grid_cols; i++)
        fprintf(stdout, "%d\t%g\n", i, temp[i]);
#endif

    free(temp);
    free(power);

    return 0;
}
